@ARTICLE{10.3389/fimmu.2026.1758743,
	author = {Hao W and Zhai S and Zhu Q and Zhou X and Shen T and He W and Sun Y and Yang W and Yang Y},
	title = {First case of TREX1 mutation-driven retinal vasculopathy with cerebral leukoencephalopathy and systemic manifestations coexisting with lupus nephritis: a case report and mechanistic discussion.},
	journal = {Front Immunol},
	year = {2026},
	abstract = {BACKGROUND: The TREX1 gene is fundamental for the removal of cytosolic DNA and the preservation of immune tolerance. Mutations within this gene are implicated in a range of disorders, such as Retinal Vasculopathy with Cerebral Leukoencephalopathy and Systemic Manifestations (RVCL-S), Aicardi-Goutières syndrome (AGS), familial chilblain lupus, and systemic lupus erythematosus (SLE). To the best of our knowledge, this report documents the rare coexistence of TREX1-associated RVCL-S and biopsy-proven lupus nephritis in a single patient. CASE PRESENTATION: We report a case involving a middle-aged woman diagnosed with lupus nephritis, confirmed through renal biopsy, who later experienced progressive neurological deficits. Brain imaging demonstrated typical signs of cerebral leukoencephalopathy. Whole-exome sequencing uncovered a pathogenic TREX1 mutation (c.811_812dup, p.Asp272Argfs*6), resulting in a diagnosis of genetically confirmed TREX1-associated RVCL-S with an incomplete phenotype, coexisting with lupus nephritis. This case underscores a significant clinical challenge: the use of immunosuppressive therapy for lupus nephritis is hypothesized to potentially exacerbate the vascular complications associated with RVCL-S. CONCLUSION: To the best of our knowledge, this case represents the first documented instance of the TREX1 p.Asp272Argfs*6 mutation contributing to the coexistence of RVCL-S and lupus nephritis. This discovery broadens the recognized phenotypic spectrum associated with TREX1-related disorders and underscores a distinct therapeutic challenge in their management. It is important for clinicians to be aware of this new phenotype to ensure prompt diagnosis and tailored treatment strategies. ER - ER - ER -},
	doi = {10.3389/fimmu.2026.1758743},
	type = {JOUR}
}

@ARTICLE{10.3389/fimmu.2026.1736522,
	author = {Luo H and Chen B and Zhang X},
	title = {Novel application for the JAK inhibitor baricitinib in the treatment of Vogt-Koyanagi-Harada disease: a prospective cohort study.},
	journal = {Front Immunol},
	year = {2026},
	abstract = {PURPOSE: The purpose of this study was to prospectively evaluate the clinical efficacy and safety of baricitinib, a selective Janus kinase (JAK)1/JAK2 inhibitor, in the treatment of patients with Vogt-Koyanagi-Harada (VKH) disease. DESIGN: The study was designed as a prospective, open-label, longitudinal, single-center cohort study. METHODS: We enrolled 38 patients (76 eyes) with VKH disease (including both initial-onset and recurrent/chronic cases) at Tongji Hospital, Wuhan, China, between 2022 and 2024. Patients were assigned to one of two treatment protocols based on disease severity and prior treatment history: group A received oral baricitinib (4 mg/day) combined with systemic methylprednisolone, and group B received oral baricitinib monotherapy. Clinical assessments were performed at baseline and at 1, 3, 6, 12, and 18 months. Primary outcome measures included best-corrected visual acuity (BCVA), anterior chamber (AC) cell and flare grades, subfoveal choroidal thickness (SFCT), subretinal fluid (SRF) height, and angiographic inflammatory scores (fluorescein angiography [FA]/indocyanine green angiography [ICGA]). Secondary outcomes included quality-of-life scores (25-item version of the Visual Function Questionnaire [VFQ-25], SF-36), adverse drug reactions (ADRs), and recurrence rates. RESULTS: The cohort included 44 eyes with early-stage (initial-onset) and 32 eyes with late-stage (recurrent) VKH disease (mean age: 43.1 years ± 12.3 years; follow-up: 6-18 months). Inflammation control was achieved in all patients in both groups. In group A, the combination therapy led to rapid resolution of inflammation. In group B (monotherapy), significant improvements were observed from baseline to the final visit, including improved BCVA (0.12 to 0.68, p < 0.001), reduced AC cell grade (1.54 to 0.05, p = 0.007), decreased SFCT (537.6 to 252.4 μm, p = 0.007), and complete resolution of SRF (p < 0.001). FA and ICGA scores significantly decreased (p < 0.05), and VFQ-25 scores improved (82.6 to 92.9, p < 0.001). No severe ADRs or disease recurrences were observed during the follow-up period. CONCLUSION: This study demonstrates that baricitinib is a promising therapeutic option for both early- and late-stage VKH disease. It effectively controls choroidal inflammation, improves visual function, and allows for a substantial reduction in corticosteroid burden with a favorable safety profile. CLINICAL TRIAL REGISTRATION: http://www.chictr.org.cn, identifier ChiCTR2100048030. ER - ER - ER -},
	doi = {10.3389/fimmu.2026.1736522},
	type = {JOUR}
}

@ARTICLE{10.3390/biomedicines14030612,
	author = {Szeretucha M and Paczwa K, Romanowska-Próchnicka K and Ornowska S, Różycki R, Gołębiewska J},
	title = {Optical Coherence Tomography Angiography in Patients with Mixed Connective Tissue Disease.},
	journal = {Biomedicines},
	year = {2026},
	abstract = {Background: Mixed connective tissue disease (MCTD) is a rare systemic autoimmune disease which presents with clinical features that overlap with at least two connective tissue disorders, including systemic lupus erythematosus (SLE), systemic sclerosis (SSc), polymyositis (PM), dermatomyositis (DM), and rheumatoid arthritis (RA). It is characterized by the presence of anti-ribonucleoprotein (anti-U1RNP) antibodies. The mechanism of the vasculopathy associated with MCTD remains largely unknown. Optical coherence tomography angiography (OCTA) is a non-invasive imaging method of the microvasculature of the retina and choroid, providing the assessment of retinal perfusion. Objectives: The aim of the study was to evaluate the optical coherence tomography angiography (OCTA) parameters in patients with mixed connective tissue disease compared to healthy individuals. Methods: In this study, we compared the following parameters between patients with MCTD and healthy subjects: foveal avascular zone (FAZ), FAZ perimeter (PERIM), flow density (FD), choriocapillaris flow area (CCFA), outer retina flow area (ORFA), and foveal and parafoveal mean superficial and deep vessel density. Results: Parafoveal mean superficial vessel density and parafoveal mean deep vessel density were significantly lower in the MCTD group than in controls. The FAZ, FAZ PERIM, and FD values in the patients with MCTD were lower than in the control group and statistically significant for all parameters. Conclusions: The present study's findings suggest the presence of ocular vascular abnormalities in patients suffering from MCTD. These abnormalities are characterized by decreased retinal vessel density and lower choriocapillaris flow. The results of the study demonstrate the significant role of OCTA in the diagnosis and monitoring of microvascular changes in patients with MCTD. ER - ER - ER -},
	doi = {10.3390/biomedicines14030612},
	type = {JOUR}
}

@ARTICLE{10.1038/s41598-026-44125-z,
	author = {Zou Q and Zhang L and Li M and Wang B and Cao Y and Zhang X and Qu J},
	title = {Correlation between anti-retinal antibodies and lupus retinopathy in systemic lupus erythematosus.},
	journal = {Sci Rep},
	year = {2026},
	abstract = {Lupus retinopathy (LR) is one of the most frequent and serious ocular complications of systemic lupus erythematosus (SLE), because it may cause irreversible visual impairment. The aim of this study was to evaluate the association between serum anti-retinal antibodies levels of SLE patients and the incidence of LR. Levels of serum anti-α-enolase antibody (Ab), anti-arrestin Ab, anti-recoverin Ab and anti-IRBP3 Ab were detected in 89 SLE patients (divided into LR group and non-LR group) and 81 healthy controls by enzyme-linked immunosorbent assay (ELISA). The correlation between these four anti-retinal Ab, SLE activity and the incidence of LR was evaluated. LR group had a higher SLE disease activity index (average SLEDAI score, 18 (7) versus 9 (5), P < 0.001), higher frequency of pleurisy (40% versus 20.4%, P = 0.044) and lower level of hemoglobin (102.343 ± 23.157 versus 112.759 ± 19.678, P = 0.025) comparing to non-LR group. LR group had higher levels of anti-α-enolase than non-LR group (P = 0.033) and control group (P < 0.0001). The levels of anti-recoverin in LR group was higher than non-LR group (P = 0.036) and control group (P < 0.0001), while the difference was not significant between non-LR group and control group (P = 0.109). Using combination of anti-α-enolase Ab and anti-recoverin Ab to diagnose LR in SLE patients is more effective (with area under the receiver operating characteristic curve (AUC): 72.68%) than use anti-α-enolase Ab (AUC: 65.65%) or anti-recoverin (AUC: 61.96%) only. Our results suggested that anti-α-enolase and anti-recoverin may be used as potential biomarkers of lupus retinopathy in SLE patients. ER - ER - ER -},
	doi = {10.1038/s41598-026-44125-z},
	type = {JOUR}
}

@ARTICLE{10.1016/j.ejca.2026.116594,
	author = {Cuzzubbo S and Vogrig A and Louis E and Philippakis E and Ursu R and Ezine E, Lebbé C and Aprile G and Couturier A and Carpentier AF},
	title = {Optic neuropathies induced by immune checkpoint inhibitors: A case series and systematic review of the literature.},
	journal = {Eur J Cancer},
	year = {2026},
	abstract = {INTRODUCTION: Immune checkpoint inhibitor (ICI)-related optic neuritis is rare but clinically significant as visual sequelae are reported in around half of affected patients. MATERIALS AND METHODS: We retrospectively collected all cases of ICI-related optic neuropathy referred to two tertiary centers. A systematic review of PubMed, Embase, and Medline was conducted following PRISMA guidelines. Cases were classified into: i) optic neuritis, defined by the presence of consistent symptoms (visual loss, dyschromatopsia, afferent pupillary defect) and optic nerve abnormalities on MRI or visual evoked potentials (VEPs); ii) papillitis, defined by any visual disturbance associated with optic disc oedema and absence of optic neuropathy signs on MRI imaging or VEPs. RESULTS: Fifty cases were identified. The most common presentation was bilateral, painless visual acuity reduction with papilledema. All optic neuritis cases involved vision loss compared to 60 % of papillitis patients, who also reported scotomas, photopsia, or floaters. Papillitis was frequently associated with uveitis, either isolated or as part of Vogt-Koyanagi-Harada-like syndrome, whereas optic neuritis was more often associated with immune-related neurological toxicities, including neuromyelitis optica spectrum disorder. Despite immunomodulatory treatment, visual deficits persisted in 60 % of cases - rising to nearly 80 % in optic neuritis cases. Seven patients with papillitis and one with optic neuropathy resumed ICIs without recurrence. CONCLUSIONS: Two distinct patterns of ICI-induced optic neuropathy emerge: papillitis, usually associated with uveitis and Vogt-Koyanagi-Harada syndrome, and optic neuritis, linked to broader immune-related neurological toxicities and poorer outcomes. Our findings suggest that ICIs may be safely reintroduced after full recovery from ICI-related papillitis. ER - ER - ER -},
	doi = {10.1016/j.ejca.2026.116594},
	type = {JOUR}
}

@ARTICLE{10.3389/fmed.2026.1755451,
	author = {Li F and Wu D and Zhu X},
	title = {Case Report: Vogt-Koyanagi-Harada syndrome complicated by secondary glaucoma: diagnostic insights and mechanistic correlations in uveitic ocular hypertension.},
	journal = {Front Med (Lausanne)},
	year = {2026},
	abstract = {INTRODUCTION: This case highlights an uncommon presentation of Vogt-Koyanagi-Harada (VKH) syndrome, in which acute angle-closure glaucoma (AACG) served as the initial ocular manifestation. This atypical onset may lead to misdiagnosis as primary angle-closure glaucoma. This report adds to the existing literature by emphasizing the diagnostic value of ciliary body imaging and the mechanistic link between inflammatory ciliary body detachment and secondary angle closure. CASE PRESENTATION: A 27-year-old woman presented with acute ocular pain, vision loss, and markedly elevated intraocular pressure (IOP). Important clinical findings included conjunctival congestion, corneal edema, medium-depth anterior chambers, and the absence of keratic precipitates or aqueous flare. Ultrasound biomicroscopy revealed a ciliary body detachment, whereas optical coherence tomography revealed multiple serous retinal detachments. The patient was initially misdiagnosed with glaucoma before a revised diagnosis of VKH syndrome-associated secondary AACG was made. INTERVENTIONS AND OUTCOMES: The patient was treated with intravenous methylprednisolone pulse therapy combined with topical corticosteroids, mydriatic agents, and IOP-lowering agents. Visual acuity and IOP gradually improved, and subretinal fluid completely resolved during follow-up. CONCLUSION: VKH syndrome rarely presents with AACG as the initial manifestation. Awareness of this presentation and careful imaging evaluation are essential to avoid misdiagnosis. Early and aggressive anti-inflammatory therapy remains key to reversing both angle closure and retinal pathology. This case highlights the importance of considering autoimmune uveitis in patients with atypical angle-closure glaucoma. ER - ER - ER -},
	doi = {10.3389/fmed.2026.1755451},
	type = {JOUR}
}

@ARTICLE{10.3389/fimmu.2026.1724780,
	author = {Triggianese P and Capparelli E and D'Antonio A and Nesi C and Lombardo M and Kroegler B and Bergamini A and Mancino R and Mitterhofer AP and Della-Morte D and Nucci C and Cesareo M and Martucci A},
	title = {Reduced retinal microvascular density in patients with mixed connective tissue disease: an exploratory pilot study on the interplay between aging, renal function, and complement system.},
	journal = {Front Immunol},
	year = {2026},
	abstract = {BACKGROUND: Mixed connective tissue disease (MCTD) is a systemic autoimmune disease with overlapping features with systemic lupus erythematosus, systemic sclerosis, and inflammatory idiopathic myopathies, characterized by anti-U1-RNP antibodies. Although subclinical retinal microvascular changes have been described in other connective tissue diseases, such data are lacking in patients with MCTD. METHODS: We performed a cross-sectional exploratory pilot study including patients with a defined diagnosis of MCTD according to one of the sets of classification criteria and age- and sex-matched healthy controls (HC), with elderly individuals equally distributed. Data on disease duration, renal function (creatinine and eGFR), and complement levels (C3 and C4) were recorded. All participants underwent optical coherence tomography angiography (OCT-A) to evaluate retinal vessel density (VD) using parafoveal, perifoveal, and foveal scans, whole images, and foveal avascular zones (FAZs). Nailfold videocapillaroscopy (NVC) was performed in patients with MCTD on four fingers of both hands to assess microangiopathy patterns. RESULTS: Patients with MCTD (n = 20, mean age 60.6 ± 11.4 years, 85% females) showed a significant reduction in both superficial and deep retinal VD across all evaluated regions compared with 20 HC. In patients with MCTD, deep retinal VD was inversely correlated with disease duration (r = -0.6, P = 0.0003) and directly correlated with eGFR (r = 0.4, P = 0.05). In patients with MCTD, C3 levels were positively correlated with age (r = 0.4, P = 0.03) and superficial parafoveal VD (r = 0.5, P = 0.008). In MCTD, NVC abnormalities, including non-specific microangiopathy and scleroderma patterns, occurred in 60% (n = 12) of cases and did not correlated with OCT-A findings. CONCLUSION: Patients with MCTD present subclinical retinal microvascular abnormalities detectable by OCT-A. Our hypothesis-generating study suggests that retinal vascular changes may be linked to disease duration, renal function, and complement levels. OCT-A may be a useful tool for assessing MCTD. ER - ER - ER -},
	doi = {10.3389/fimmu.2026.1724780},
	type = {JOUR}
}

@ARTICLE{10.1016/j.preteyeres.2026.101445,
	author = {Xia L and Chen L and Dai L and Zhang P, Cifuentes-González C and Gupta V and Agrawal R and Yang P},
	title = {Vogt-Koyanagi-Harada disease under the lens: Insights from multimodal ocular imaging.},
	journal = {Prog Retin Eye Res},
	year = {2026},
	abstract = {Vogt-Koyanagi-Harada (VKH) disease is a multisystem autoimmune condition targeting melanocyte-rich ocular tissues, with inflammation primarily affecting the choroid. Despite advances in diagnostic criteria, disease staging and therapeutic decisions still rely heavily on clinical observation, with limited integration of imaging biomarkers. This review examines the evolving role of multimodal ocular imaging (MMI) in the diagnosis, monitoring, and prognostication of VKH. We critically appraise the utility and limitations of color fundus photography, fluorescein angiography (FFA), indocyanine green angiography (ICGA), optical coherence tomography (OCT), OCT angiography (OCTA), fundus autofluorescence, B-scan ultrasonography, ultrasound biomicroscopy and anterior segment photography. These modalities provide complementary insights into disease activity, from subclinical choroiditis and retinal pigment epithelium disruption to chronic sequelae such as subretinal fibrosis and choroidal atrophy. Key imaging features-such as choroidal thickening, hypofluorescent dark dots, RPE undulations, and flow voids-are described in the context of VKH pathophysiology and disease stage. We identify critical gaps in current practice, including the lack of standardized imaging-based definitions for relapse and remission, limited use of anterior segment imaging, and variability in access to advanced modalities. To address these challenges, we propose a stage-specific imaging framework to guide VKH assessment from prodromal to chronic phases. MMI has transitioned from a supportive to a central role in VKH management. Future efforts should prioritize the development of quantitative imaging biomarkers, standardization of grading systems, and integration of imaging into therapeutic algorithms to support timely, personalized care and prevent irreversible visual loss. ER - ER - ER -},
	doi = {10.1016/j.preteyeres.2026.101445},
	type = {JOUR}
}

@ARTICLE{10.1016/j.ajo.2025.10.028,
	author = {Samalia PD and Sims JL and Tomkins-Netzer O and Lightman SL and Niederer RL},
	title = {Sex-Related Effects on the Clinical Presentation of Uveitis.},
	journal = {Am J Ophthalmol},
	year = {2026},
	abstract = {OBJECTIVE/PURPOSE: The primary aim of this study was to determine sex-related patterns of uveitic entities. Secondary aims included sex-related patterns of uveitic complications. DESIGN: Retrospective clinical cohort study. PARTICIPANTS: 5703 participants presenting with uveitis from January 2009 to December 2023 were included. MAIN OUTCOME MEASURES: uveitis entities and complications. RESULTS: 2870 (50.3%) participants were female and 2831 (49.6%) were male. Males presented at a significantly younger age than females (42.2 vs 45.0). Significant sex-based differences were observed in the prevalence of specific uveitic conditions. Females were more likely to develop multifocal choroiditis (female: male ratio 1.818:1), Vogt-Koyanagi-Harada syndrome (female: male ratio 2.136:1), birdshot chorioretinopathy (female: male ratio 2.800:1, punctate inner choroidopathy (female: male ratio 6.571:1), drug-induced uveitis (female: male ratio 2.833:1), Crohn's disease (female: male ratio 3.714:1) and multiple evanescent white dot syndrome (female: male ratio 5.000:1). In contrast, males were more likely to develop acute posterior multifocal placoid pigment epitheliopathy (female: male ratio 0.364:1), sympathetic ophthalmia (female: male ratio 0.353:1) and syphilis (female: male ratio 0.404:1). Cataract was significantly more common in females, and this remained significant after adjusting for age at presentation, anatomical location and bilaterality. Cystoid macular edema and epiretinal membrane were more frequent in females, whereas retinal detachment occurred more often in males. Bilateral vision loss occurred in 238 patients (4.2%) and was significantly more common in females (4.9% vs 3.5%). CONCLUSIONS: Sex appears to be a key factor influencing the underlying etiology and clinical course of uveitis. These findings underscore the importance of considering sex as a biological variable in the diagnosis, monitoring, and management of uveitis. ER - ER - ER -},
	doi = {10.1016/j.ajo.2025.10.028},
	type = {JOUR}
}

@ARTICLE{10.3389/fmed.2026.1733153,
	author = {Huang Y and Wang Y and Ren Q},
	title = {Co-occurrence of Vogt-Koyanagi-Harada disease, diabetic retinopathy, and advanced chronic kidney disease: a case report.},
	journal = {Front Med (Lausanne)},
	year = {2026},
	abstract = {OBJECTIVE: This study aimed to report a case of Vogt-Koyanagi-Harada (VKH) disease in a 53-year-old man with renal failure and diabetes, highlighting the challenges in diagnosing VKH amidst complex systemic comorbidities. METHODS: A case report was conducted through a retrospective review of the patient's medical history, clinical presentations, diagnostic workup, and treatment course. RESULTS: A 53-year-old man with renal failure, hypoalbuminemia, and diabetes presented with blurred vision. Initial findings included bilateral serous retinal detachment with subretinal septa, choroidal thickening, and left eye vitreous hemorrhage, without anterior chamber inflammation. Subsequent anterior segment inflammation and a positive response to combined corticosteroids and adalimumab confirmed VKH. CONCLUSION: This case underscores the diagnostic complexity of VKH in patients with multiple systemic conditions. Corticosteroid management in such individuals requires meticulous attention, emphasizing the need for close monitoring of blood glucose and overall systemic status during treatment. ER - ER - ER -},
	doi = {10.3389/fmed.2026.1733153},
	type = {JOUR}
}

@ARTICLE{10.1038/s41598-025-34652-6,
	author = {Nakamura T and Abe S and Oiwake T and Hayashi A},
	title = {Retinal structure and function recovery over five years in Vogt-Koyanagi-Harada disease using adaptive optics and microperimetry.},
	journal = {Sci Rep},
	year = {2026},
	abstract = {Vogt-Koyanagi-Harada (VKH) disease recovery patterns remain inadequately characterized over extended periods. This study evaluated retinal changes in VKH patients across 5 years using adaptive optics imaging and microperimetry. Twenty-five eyes from 13 patients were monitored longitudinally. Macular cone density gradually increased throughout the observation period but remained below healthy control levels. Eyes with pretreatment cystoid spaces initially showed lower cone density values, but this disparity disappeared after 3 years. Average threshold values improved consistently from baseline, while macular integrity values significantly decreased after 2 years. Cone density correlated significantly with retinal sensitivity. These findings indicate that with appropriate treatment, VKH disease demonstrates progressive improvement in both retinal structure and function over time, though complete structural recovery may not occur. Pretreatment cystoid spaces influence early outcomes but do not significantly affect long-term recovery. SUPPLEMENTARY INFORMATION: The online version contains supplementary material available at 10.1038/s41598-025-34652-6. ER - ER - ER -},
	doi = {10.1038/s41598-025-34652-6},
	type = {JOUR}
}
